CREATE TYPE IF NOT EXISTS "public"."accessory_return_status" AS ENUM('ok', 'danificado', 'perdido', 'roubado');
CREATE TYPE IF NOT EXISTS "public"."contract_status" AS ENUM('ativo', 'parcialmente_devolvido', 'encerrado');
CREATE TYPE IF NOT EXISTS "public"."maintenance_status" AS ENUM('em_andamento', 'concluida');
CREATE TYPE IF NOT EXISTS "public"."nacionalidade" AS ENUM('brasileiro', 'estrangeiro');
CREATE TYPE IF NOT EXISTS "public"."tipo_documento" AS ENUM('cpf', 'passaporte');

CREATE TABLE IF NOT EXISTS "audit_logs" (
  "id" serial PRIMARY KEY NOT NULL,
  "adminId" integer,
  "acao" varchar(100) NOT NULL,
  "tabela" varchar(50) NOT NULL,
  "registroId" integer,
  "dadosAntes" jsonb,
  "dadosDepois" jsonb,
  "ip" varchar(45),
  "criadoEm" timestamp DEFAULT now() NOT NULL
);

CREATE TABLE IF NOT EXISTS "bike_maintenance_logs" (
  "id" serial PRIMARY KEY NOT NULL,
  "bikeId" integer NOT NULL,
  "descricao" text NOT NULL,
  "custo" numeric(10, 2),
  "dataEntrada" timestamp DEFAULT now() NOT NULL,
  "dataPrevistaRetorno" timestamp,
  "status" "maintenance_status" DEFAULT 'em_andamento' NOT NULL,
  "fotos" jsonb,
  "createdAt" timestamp DEFAULT now() NOT NULL,
  "updatedAt" timestamp DEFAULT now() NOT NULL
);

CREATE TABLE IF NOT EXISTS "bike_sizes" (
  "id" serial PRIMARY KEY NOT NULL,
  "bikeId" integer NOT NULL,
  "tamanho" varchar(20) NOT NULL,
  "quantidadeTotal" integer DEFAULT 1 NOT NULL,
  "quantidadeDisponivel" integer DEFAULT 1 NOT NULL,
  "observacao" text,
  "createdAt" timestamp DEFAULT now() NOT NULL
);

CREATE TABLE IF NOT EXISTS "contract_accessories" (
  "id" serial PRIMARY KEY NOT NULL,
  "contractId" integer NOT NULL,
  "accessoryId" integer NOT NULL,
  "qty" integer DEFAULT 1 NOT NULL,
  "status" "accessory_return_status" DEFAULT 'ok' NOT NULL,
  "observacao" text,
  "fotoUrl" text
);

CREATE TABLE IF NOT EXISTS "contracts" (
  "id" serial PRIMARY KEY NOT NULL,
  "clientId" integer NOT NULL,
  "status" "contract_status" DEFAULT 'ativo' NOT NULL,
  "valorTotal" numeric(10, 2),
  "pdfUrl" text,
  "criadoEm" timestamp DEFAULT now() NOT NULL,
  "encerradoEm" timestamp,
  "deletedAt" timestamp,
  "pendenciaAcessorio" boolean DEFAULT false NOT NULL
);

ALTER TABLE "accessories" ALTER COLUMN "category" SET DATA TYPE varchar(50);
ALTER TABLE "accessories" ADD COLUMN IF NOT EXISTS "quantidadeTotal" integer DEFAULT 1 NOT NULL;
ALTER TABLE "accessories" ADD COLUMN IF NOT EXISTS "quantidadeDisponivel" integer DEFAULT 1 NOT NULL;
ALTER TABLE "clients" ADD COLUMN IF NOT EXISTS "nacionalidade" "nacionalidade";
ALTER TABLE "clients" ADD COLUMN IF NOT EXISTS "tipo_documento" "tipo_documento";
ALTER TABLE "clients" ADD COLUMN IF NOT EXISTS "numero_passaporte" varchar(50);
ALTER TABLE "clients" ADD COLUMN IF NOT EXISTS "deletedAt" timestamp;
ALTER TABLE "rentals" ADD COLUMN IF NOT EXISTS "source" "client_source" DEFAULT 'manual';
ALTER TABLE "rentals" ADD COLUMN IF NOT EXISTS "contractId" integer;
ALTER TABLE "rentals" ADD COLUMN IF NOT EXISTS "deletedAt" timestamp;

